import * as fs from "fs";
import * as path from "path";

export interface DiffResult {
  added: string[];
  modified: string[];
  deleted: string[];
  all: string[];
}

export interface IndexedCommit {
  hash: string;
  timestamp: string;
  branch: string;
}

interface TrackingStore {
  lastIndexedCommit: IndexedCommit | null;
}

function runGit(cwd: string, args: string): string {
  try {
    return execSync(`git ${args}`, {
      cwd,
      encoding: "utf-8",
      stdio: ["pipe", "pipe", "pipe"],
    }).trim();
  } catch {
    throw new Error(`git ${args} failed in ${cwd}`);
  }
}

function currentBranch(cwd: string): string {
  try {
    return runGit(cwd, "rev-parse --abbrev-ref HEAD");
  } catch {
    return "unknown";
  }
}

function parseDiffNames(raw: string): string[] {
  return raw
    .split("\n")
    .map((l) => l.trim())
    .filter(Boolean);
}

function classifyFiles(
  addedRaw: string,
  modifiedRaw: string,
  deletedRaw: string
): DiffResult {
  const added = parseDiffNames(addedRaw);
  const modified = parseDiffNames(modifiedRaw);
  const deleted = parseDiffNames(deletedRaw);
  const all = [...added, ...modified, ...deleted];
  return { added, modified, deleted, all };
}

export class GitDiffTracker {
  private repoPath: string;
  private storePath: string;

  constructor(repoPath: string, storePath: string) {
    this.repoPath = path.resolve(repoPath);
    this.storePath = path.resolve(storePath);
  }

  private loadStore(): TrackingStore {
    if (!fs.existsSync(this.storePath)) {
      return { lastIndexedCommit: null };
    }
    try {
      const data = JSON.parse(fs.readFileSync(this.storePath, "utf-8"));
      return data as TrackingStore;
    } catch {
      return { lastIndexedCommit: null };
    }
  }

  private saveStore(store: TrackingStore): void {
    const dir = path.dirname(this.storePath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
    fs.writeFileSync(this.storePath, JSON.stringify(store, null, 2), "utf-8");
  }

